func isPrivateIP(ip net.IP) bool {
	ip = ip.To4()
	if ip == nil {
		// IPv6 checks
		return isPrivateIPv6(net.ParseIP(ip.String()))
	}

	switch {
	case ip[0] == 10:
		return true
	case ip[0] == 127:
		return true
	case ip[0] == 0:
		return true
	case ip[0] == 169 && ip[1] == 254:
		return true
	case ip[0] == 172 && ip[1] >= 16 && ip[1] <= 31:
		return true
	case ip[0] == 192 && ip[1] == 168:
		return true
	case ip[0] >= 224:
		return true
	}
	return false
}

func isPrivateIPv6(ip net.IP) bool {
	if ip == nil {
		return false
	}
	// Loopback ::1
	if ip.IsLoopback() {
		return true
	}
	// Unique local fc00::/7
	if len(ip) == net.IPv6len && (ip[0]&0xfe) == 0xfc {
		return true
	}
	// Link-local fe80::/10
	if len(ip) == net.IPv6len && ip[0] == 0xfe && (ip[1]&0xc0) == 0x80 {
		return true
	}
	// Multicast ff00::/8
	if len(ip) == net.IPv6len && ip[0] == 0xff {
		return true
	}
	return false
}

